import{_ as r,a as i,b as a}from"./chunks/0_H84UsJVgH3V5j96h.14oI3MBq.js";import{_ as t,c as o,o as n,ag as s}from"./chunks/framework.S-Qvb3wi.js";const b=JSON.parse('{"title":"AI 아레나","description":"","frontmatter":{},"headers":[],"relativePath":"kr/AI-Arena.md","filePath":"kr/AI-Arena.md"}'),e={name:"kr/AI-Arena.md"};function g(u,l,d,h,p,c){return n(),o("div",null,l[0]||(l[0]=[s('<h1 id="ai-아레나" tabindex="-1">AI 아레나 <a class="header-anchor" href="#ai-아레나" aria-label="Permalink to &quot;AI 아레나&quot;">​</a></h1><p><strong>DGrid AI 아레나</strong>는 DGrid 플랫폼 내의 전용 허브로, 사용자가 DGrid의 AI 모델을 평가하고 개선하는 데 도움을 주며, 기여도에 따라 온체인 보상을 받을 수 있습니다.</p><p>간단한 일일 &quot;AI 배틀&quot;을 완료하고 새 사용자를 초대하면, 참가자는 다음과 같은 혜택을 얻을 수 있습니다:</p><ul><li>실제 AI 모델 응답을 비교하고 더 우수한 응답을 표시</li><li>각 의사결정 및 추천 행위마다 포인트 획득</li><li>포인트를 <strong>USDT</strong>로 전환</li><li><strong>주간 리더보드</strong>에 참여해 공유 상금 풀을 분배받기</li></ul><p>DGrid AI 아레나는 단순한 게임화 계층이 아닙니다. 이는 커뮤니티의 판단을 활용해 다음을 달성하는 DGrid AI 인프라의 핵심 구성 요소입니다:</p><ul><li>모델 품질 평가</li><li>모델 최적화 및 배포 방향 설정</li><li>DGrid AI를 실제 사용자 기대치와 지속적으로 일치시키기</li></ul><h2 id="핵심-개념" tabindex="-1">핵심 개념 <a class="header-anchor" href="#핵심-개념" aria-label="Permalink to &quot;핵심 개념&quot;">​</a></h2><h4 id="ai-아레나-1" tabindex="-1">AI 아레나 <a class="header-anchor" href="#ai-아레나-1" aria-label="Permalink to &quot;AI 아레나&quot;">​</a></h4><p><strong>AI 아레나</strong>는 DGrid 내 모든 AI 보상 및 평가 활동이 진행되는 진입점입니다. 다음을 제공합니다:</p><ul><li>​<strong>AI 배틀</strong>​: 사용자가 AI 답변을 비교하는 일일 미션</li><li>​<strong>포인트 및 보상</strong>​: 획득한 포인트, 환전 내역, 리더보드 순위 추적</li></ul><p>DGrid 인터페이스를 통해 AI 아레나에 접속하거나, 직접 다음 주소로 방문할 수 있습니다: <a href="https://dgrid.ai/arena" target="_blank" rel="noreferrer"><code>https://dgrid.ai/arena</code></a></p><h4 id="ai-배틀" tabindex="-1">AI 배틀 <a class="header-anchor" href="#ai-배틀" aria-label="Permalink to &quot;AI 배틀&quot;">​</a></h4><p><strong>AI 배틀</strong>은 DGrid AI 아레나의 주요 상호작용 흐름입니다. 사용자는:</p><ul><li>무작위 질문 또는 프롬프트를 수신</li><li><strong>두 개의 익명 AI 모델 응답</strong> 확인</li><li>자신이 더 우수하다고 판단하는 답변 선택</li></ul><p>각 의사결정은 포인트를 제공하며, DGrid의 모델 평가 및 학습 파이프라인에 반영됩니다.</p><h4 id="포인트" tabindex="-1">포인트 <a class="header-anchor" href="#포인트" aria-label="Permalink to &quot;포인트&quot;">​</a></h4><p><strong>포인트</strong>는 DGrid AI 아레나에서 기여도를 측정하는 내부 지표입니다. 주요 특징은 다음과 같습니다:</p><ul><li>획득 방식: <ul><li>일일 AI 배틀 미션 완료</li><li>새 사용자 추천</li></ul></li><li>사용 방식: <ul><li>USDT로 직접 전환</li><li>주간 리더보드 상금 풀 분배 비율 결정</li></ul></li></ul><h4 id="보상-usdt-주간-상금-풀" tabindex="-1">보상 (USDT &amp; 주간 상금 풀) <a class="header-anchor" href="#보상-usdt-주간-상금-풀" aria-label="Permalink to &quot;보상 (USDT &amp; 주간 상금 풀)&quot;">​</a></h4><p>DGrid AI 아레나는 참여자에게 ​<strong>실제 온체인 가치</strong>​를 보상으로 제공합니다:</p><ul><li>누적 포인트 기반 <strong>직접 USDT 환전</strong></li><li>공유 <strong>300달러 상금 풀</strong>에서 제공되는 <strong>주간 리더보드 보상</strong></li></ul><h2 id="ai-배틀-작동-방식" tabindex="-1">AI 배틀 작동 방식 <a class="header-anchor" href="#ai-배틀-작동-방식" aria-label="Permalink to &quot;AI 배틀 작동 방식&quot;">​</a></h2><h3 id="일일-미션" tabindex="-1">일일 미션 <a class="header-anchor" href="#일일-미션" aria-label="Permalink to &quot;일일 미션&quot;">​</a></h3><ul><li>각 사용자는 매일 최대 ​<strong>5개의 일일 미션</strong>​을 완료할 수 있습니다.</li><li>모든 미션은 ​<strong>빠르고 직관적</strong>​으로 설계되어 짧은 시간만 소요됩니다.</li><li>미션은 매일 초기화되어, 사용자가 지속적으로 참여하도록 유도합니다.</li></ul><h3 id="미션-흐름" tabindex="-1">미션 흐름 <a class="header-anchor" href="#미션-흐름" aria-label="Permalink to &quot;미션 흐름&quot;">​</a></h3><p>각 미션은 다음 단계로 진행됩니다:</p><ol><li><strong>프롬프트 표시</strong></li></ol><ul><li>사용자에게 ​<em>무작위 질문 또는 프롬프트</em>​가 표시됩니다.</li></ul><ol start="2"><li><strong>두 개의 익명 AI 응답</strong></li></ol><ul><li>프롬프트 뒤에는 ​<strong>두 개의 AI 답변</strong>​이 표시되며, 각 답변은 서로 다른 모델에서 생성된 것일 수 있습니다.</li><li>모델은 익명 처리되며, 오직 답변 내용만 확인할 수 있습니다.</li></ul><ol start="3"><li><strong>사용자 선택</strong></li></ol><ul><li>사용자는 두 답변을 주의 깊게 읽습니다.</li><li>사용자는 다음 기준에 맞는 답변을 선택합니다: <ul><li>프롬프트에 더 잘 부합하는 답변</li><li>자신의 기대치 또는 필요에 더 잘 부합하는 답변</li></ul></li></ul><ol start="4"><li><strong>커뮤니티 합의 기반 포인트 지급</strong></li></ol><ul><li>충분한 사용자가 투표한 후, 해당 미션에 대한 <strong>커뮤니티 다수 의견</strong>이 형성됩니다.</li><li>사용자의 보상은 자신의 선택이 이 다수 의견과 일치하는지 여부에 따라 결정됩니다 (자세한 내용은 다음 섹션 참고).</li></ul><h3 id="모델-학습-및-평가에서의-역할" tabindex="-1">모델 학습 및 평가에서의 역할 <a class="header-anchor" href="#모델-학습-및-평가에서의-역할" aria-label="Permalink to &quot;모델 학습 및 평가에서의 역할&quot;">​</a></h3><p>AI 배틀에서의 각 투표는 DGrid AI 네트워크의 <strong>데이터 포인트</strong>입니다. DGrid는 이러한 사용자 선택을 집계하여 다음을 수행합니다:</p><ul><li><strong>모델 성능 평가</strong>: 일관되게 우수한 답변을 생성하는 모델 식별</li><li><strong>사용자 선호도 이해</strong>: 사용자가 명확성, 유용성, 안전성, 관련성 측면에서 중요하게 생각하는 요소 파악</li><li><strong>모델 진화 방향 설정</strong>: 성능이 우수한 모델 우선순위 부여; 파인튜닝 전략 및 배포 의사결정에 정보 제공</li></ul><p>대규모로 운영될 경우, 수천 명의 사용자가 매일 내리는 수천 건의 미세한 의사결정은 강력한 ​<strong>인간 피드백 신호</strong>​를 형성하여 DGrid가 다음을 달성하도록 지원합니다:</p><ul><li>더 <strong>신뢰성 높고, 인간과 일치하는 AI 대형 언어 모델(LLM) 네트워크</strong> 구축</li><li>다양한 질문 유형에 대한 견고성 향상</li><li>정적 벤치마크를 넘어 <strong>지속적인 실시간 평가</strong> 구현</li></ul><h2 id="포인트-시스템" tabindex="-1">포인트 시스템 <a class="header-anchor" href="#포인트-시스템" aria-label="Permalink to &quot;포인트 시스템&quot;">​</a></h2><h3 id="포인트-획득-방식" tabindex="-1">포인트 획득 방식 <a class="header-anchor" href="#포인트-획득-방식" aria-label="Permalink to &quot;포인트 획득 방식&quot;">​</a></h3><p>DGrid AI 아레나에서 포인트를 획득하는 주요 방식은 두 가지입니다:</p><ol><li><strong>AI 배틀 일일 미션</strong></li></ol><ul><li>각 미션은 ​<strong>5~10포인트</strong>​를 제공합니다: <ul><li>선택이 <strong>커뮤니티 다수 의견</strong>과 일치할 경우 <strong>10포인트</strong></li><li>선택이 다수 의견과 <strong>일치하지 않을 경우</strong> <strong>5포인트</strong></li></ul></li><li>&quot;잘못된&quot; 참여는 없습니다: <ul><li>다수 의견과 다른 선택을 하더라도 포인트를 획득할 수 있습니다</li><li>모든 투표는 귀중한 피드백으로 간주됩니다</li></ul></li><li>매일 ​<strong>최대 5개의 미션</strong>​을 통해 사용자는 모델 학습에 기여하면서 포인트를 꾸준히 누적할 수 있습니다.</li></ul><ol start="2"><li><strong>추천 포인트</strong></li></ol><ul><li>사용자는 다른 이들을 DGrid AI 아레나에 초대할 수 있습니다.</li><li><strong>유효한 추천 사용자 한 명당</strong> 추천인은 ​최대​<strong>100포인트</strong>​를 획득합니다.</li><li>추천 기능을 통해 사용자는 본인의 활동뿐만 아니라 ​<strong>커뮤니티 성장을 통해 보상을 확대</strong>​할 수 있습니다.</li></ul><h3 id="포인트-사용-방식" tabindex="-1">포인트 사용 방식 <a class="header-anchor" href="#포인트-사용-방식" aria-label="Permalink to &quot;포인트 사용 방식&quot;">​</a></h3><p><strong>총 포인트</strong>는 두 가지 핵심 목적에 사용됩니다:</p><ul><li><strong>직접 USDT 환전</strong></li><li><strong>리더보드 순위 및 주간 상금 풀 분배 비율 결정</strong></li></ul><p>미션과 추천을 통해 획득한 포인트가 많을수록:</p><ul><li>환전할 수 있는 USDT 양이 더 많아집니다</li><li>주간 리더보드에서의 상대적 순위가 높아집니다</li><li>주간 상금 풀에서의 분배 비율이 더 커집니다</li></ul><h2 id="보상-모델" tabindex="-1">보상 모델 <a class="header-anchor" href="#보상-모델" aria-label="Permalink to &quot;보상 모델&quot;">​</a></h2><h3 id="직접-환전-포인트-→-usdt" tabindex="-1">직접 환전: 포인트 → USDT <a class="header-anchor" href="#직접-환전-포인트-→-usdt" aria-label="Permalink to &quot;직접 환전: 포인트 → USDT&quot;">​</a></h3><p>사용자는 포인트를 고정 환율로 <strong>USDT</strong>로 직접 전환할 수 있습니다:</p><ul><li>​<strong>환전율</strong>​: <ul><li>`1,000 포인트 = 1 USDT`</li></ul></li><li>​<strong>최소 환전 금액</strong>​: <ul><li><strong>1,000 포인트</strong> (1 USDT에 해당)</li></ul></li><li>​<strong>환전 결과</strong>​: <ul><li>환전 완료 후, USDT는 DGrid에 연결된 사용자의 지갑에 <strong>직접 전송</strong>됩니다.</li></ul></li></ul><p>이를 통해 노력과 수익 간에 <strong>명확하고 투명한</strong> 관계가 형성됩니다:</p><blockquote><p>더 많은 미션 완료 + 더 많은 추천 → 더 많은 포인트 → 지갑에 더 많은 USDT 적립.</p></blockquote><h3 id="주간-리더보드-경쟁형-보상" tabindex="-1">주간 리더보드: 경쟁형 보상 <a class="header-anchor" href="#주간-리더보드-경쟁형-보상" aria-label="Permalink to &quot;주간 리더보드: 경쟁형 보상&quot;">​</a></h3><p>직접 환전 외에도, DGrid AI 아레나는 가장 활발하고 영향력 있는 참여자를 보상하기 위해 <strong>주간 리더보드</strong>를 운영합니다.</p><ul><li>​<strong>주간 상금 풀</strong>​: <ul><li>매주 <strong>300달러</strong></li></ul></li><li>​<strong>분배 메커니즘</strong>​: <ul><li>상위 참여자가 <strong>300달러</strong> 풀을 분배받습니다</li><li>보상은 ​<strong>주간 획득 포인트에 비례</strong>​합니다: <ul><li>해당 주에 획득한 포인트가 많을수록</li><li><strong>300달러</strong> 풀에서의 분배 비율이 더 커집니다</li></ul></li></ul></li></ul><h3 id="보상-구조-요약" tabindex="-1">보상 구조 요약 <a class="header-anchor" href="#보상-구조-요약" aria-label="Permalink to &quot;보상 구조 요약&quot;">​</a></h3><ul><li><strong>캐주얼 사용자</strong><ul><li>지속적인 일일 미션 완료를 통해 보상을 획득</li><li>시간이 지남에 따라 포인트를 USDT로 환전 가능</li></ul></li><li><strong>파워 유저 &amp; 최고 기여자</strong><ul><li>다음 두 가지 혜택을 동시에 받을 수 있습니다: <ul><li>직접 USDT 환전</li><li>리더보드 보상으로 추가 수익 획득</li></ul></li></ul></li></ul><p>이 <strong>이중 보상 메커니즘</strong>은 모든 참여를 인정하는 동시에, ​<strong>지속적이고 고영향력의 참여를 유도</strong>​합니다.</p><h2 id="dgrid-ai-아레나-사용-시작하기" tabindex="-1">DGrid AI 아레나 사용 시작하기 <a class="header-anchor" href="#dgrid-ai-아레나-사용-시작하기" aria-label="Permalink to &quot;DGrid AI 아레나 사용 시작하기&quot;">​</a></h2><h3 id="단계-1-ai-아레나-접속" tabindex="-1">단계 1: AI 아레나 접속 <a class="header-anchor" href="#단계-1-ai-아레나-접속" aria-label="Permalink to &quot;단계 1: AI 아레나 접속&quot;">​</a></h3><p>​<strong>AI 아레나</strong>​로 이동하세요: <a href="https://dgrid.ai/arena" target="_blank" rel="noreferrer"><code>https://dgrid.ai/arena</code></a>.</p><p>접속 후:</p><ul><li><strong>지갑 연결</strong></li><li><strong>아레나 접속 권한 활성화</strong></li></ul><p><img src="'+r+'" alt=""></p><h3 id="단계-2-ai-배틀-시작" tabindex="-1">단계 2: AI 배틀 시작 <a class="header-anchor" href="#단계-2-ai-배틀-시작" aria-label="Permalink to &quot;단계 2: AI 배틀 시작&quot;">​</a></h3><p><strong>「AI 배틀 시작」<strong>을 클릭하세요. 미션이 시작되면: <strong>질문/프롬프트</strong>와 ​</strong>두 개의 익명 AI 응답</strong>​이 표시됩니다. 두 답변을 주의 깊게 읽고 더 우수하다고 판단하는 답변을 선택하세요. 각 미션 완료 시:</p><ul><li>커뮤니티 합의와의 일치 여부에 따라 ​<strong>5~10포인트</strong>​를 획득합니다.</li><li><strong>하루 최대 5개의 미션</strong>을 완료할 수 있습니다.</li></ul><p><img src="'+i+'" alt=""></p><h3 id="단계-3-매일-참여" tabindex="-1">단계 3: 매일 참여 <a class="header-anchor" href="#단계-3-매일-참여" aria-label="Permalink to &quot;단계 3: 매일 참여&quot;">​</a></h3><p>매일 돌아와서:</p><ul><li><strong>5개의 일일 미션</strong> 완료</li><li>더 많은 포인트 누적</li><li>DGrid AI 학습 및 개선에 지속적으로 기여</li></ul><p><img src="'+a+'" alt=""></p><h3 id="단계-4-친구-초대-추천" tabindex="-1">단계 4: 친구 초대 (추천) <a class="header-anchor" href="#단계-4-친구-초대-추천" aria-label="Permalink to &quot;단계 4: 친구 초대 (추천)&quot;">​</a></h3><p>DGrid UI의 추천 기능을 통해 네트워크에 DGrid AI 아레나를 공유하세요. <strong>유효한 추천 사용자 한 명당</strong> 추천인은 ​최대​<strong>100포인트</strong>​를 받습니다.</p><p>추천은 다음에 도움을 줍니다:</p><ul><li><strong>DGrid 커뮤니티</strong> 성장</li><li><strong>AI 배틀 피드백의 양과 다양성</strong> 증가</li><li>본인의 포인트 및 보상 증대</li></ul><h3 id="단계-5-포인트-환전-리더보드-순위-추적" tabindex="-1">단계 5: 포인트 환전 &amp; 리더보드 순위 추적 <a class="header-anchor" href="#단계-5-포인트-환전-리더보드-순위-추적" aria-label="Permalink to &quot;단계 5: 포인트 환전 &amp; 리더보드 순위 추적&quot;">​</a></h3><p>DGrid 인터페이스에서 <strong>총 포인트</strong>를 모니터링하세요. 포인트가 최소 ​<strong>1,000포인트</strong>​에 도달하면: <code>1,000 : 1 USDT</code> 비율로 <strong>USDT</strong>로 환전할 수 있습니다. <strong>주간 리더보드</strong>를 확인하여 다음을 볼 수 있습니다:</p><ul><li>다른 참여자에 대한 본인의 상대적 순위</li><li><strong>300달러</strong> 주간 상금 풀에서의 잠재적 분배 비율</li></ul><h2 id="dgrid-ai-아레나의-중요성" tabindex="-1">DGrid AI 아레나의 중요성 <a class="header-anchor" href="#dgrid-ai-아레나의-중요성" aria-label="Permalink to &quot;DGrid AI 아레나의 중요성&quot;">​</a></h2><p>DGrid AI 아레나는 DGrid의 AI 인프라 위에 구축된 <strong>협업 지능 계층</strong>입니다. 다음과 같은 목적으로 설계되었습니다:</p><ul><li>실제 사용자 기대치와 더 <strong>일치하도록</strong> 만듦</li><li>다양한 질문 및 콘텐츠 유형에 대한 견고성 향상</li><li>​<strong>실시간 실세계 피드백</strong>​에 의해 주도되는 지속적인 개선</li></ul><h3 id="대규모-인간-판단" tabindex="-1">대규모 인간 판단 <a class="header-anchor" href="#대규모-인간-판단" aria-label="Permalink to &quot;대규모 인간 판단&quot;">​</a></h3><p>다음을 결합함으로써:</p><ul><li>수천 건의 일일 미세 의사결정으로부터의 인간 판단</li><li>커뮤니티 주도型 모델 품질 평가</li><li>USDT와 연결된 투명한 온체인 보상 메커니즘</li></ul><p>DGrid는 다음을 달성할 수 있습니다:</p><ul><li>우선순위를 부여하고 배포할 모델 결정</li><li>사용자가 명확성, 유용성, 안전성, 관련성 측면에서 중요하게 생각하는 요소 파악</li><li>생태계 전반에 걸쳐 새로운 기능을 롤아웃할 시기와 방식 결정</li></ul><p>획득한 각 포인트는 단순한 숫자가 아닙니다 — 이는 다음을 결정하는 데 도움이 되는 ​<strong>신호</strong>​입니다:</p><ul><li>헤드투헤드 비교에서 어떤 모델이 &quot;승리&quot;하는지</li><li>모델을 어떻게 <strong>파인튜닝</strong>해야 하는지</li><li>어떤 행동을 <strong>강화하거나 억제</strong>해야 하는지</li></ul><p>이런 방식으로, ​<strong>각 사용자의 선택은 더 나은 AI를 위한 투표가 됩니다</strong>​.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h4 id="ai-배틀에-잘못된-선택이-있나요" tabindex="-1">AI 배틀에 &quot;잘못된&quot; 선택이 있나요? <a class="header-anchor" href="#ai-배틀에-잘못된-선택이-있나요" aria-label="Permalink to &quot;AI 배틀에 &quot;잘못된&quot; 선택이 있나요?&quot;">​</a></h4><p>없습니다. &quot;잘못된&quot; 참여는 없습니다.</p><ul><li>선택이 ​<strong>커뮤니티 다수 의견</strong>​와 일치하면 ​<strong>10포인트</strong>​를 획득합니다.</li><li>선택이 다수 의견과 <strong>일치하지 않아도</strong> 여전히 ​<strong>5포인트</strong>​를 획득합니다.</li></ul><p>각 의사결정은 모델 평가를 위한 귀중한 신호로 간주됩니다.</p><h4 id="하루에-몇-개의-미션을-완료할-수-있나요" tabindex="-1">하루에 몇 개의 미션을 완료할 수 있나요? <a class="header-anchor" href="#하루에-몇-개의-미션을-완료할-수-있나요" aria-label="Permalink to &quot;하루에 몇 개의 미션을 완료할 수 있나요?&quot;">​</a></h4><p>하루에 AI 배틀에서 <strong>최대 5개의 일일 미션</strong>을 완료할 수 있습니다.</p><h4 id="추천-포인트는-어떻게-획득하나요" tabindex="-1">추천 포인트는 어떻게 획득하나요? <a class="header-anchor" href="#추천-포인트는-어떻게-획득하나요" aria-label="Permalink to &quot;추천 포인트는 어떻게 획득하나요?&quot;">​</a></h4><p>DGrid 인터페이스의 추천 기능을 사용하여 다른 이들을 DGrid AI 아레나에 초대하세요. <strong>유효한 추천 사용자 한 명당 ​최대</strong> ​<strong>100포인트</strong> ​를 받습니다.</p><h4 id="포인트를-usdt로-어떻게-전환하나요" tabindex="-1">포인트를 USDT로 어떻게 전환하나요? <a class="header-anchor" href="#포인트를-usdt로-어떻게-전환하나요" aria-label="Permalink to &quot;포인트를 USDT로 어떻게 전환하나요?&quot;">​</a></h4><ul><li>포인트는 <code>1,000 포인트 = 1 USDT</code>의 고정 환율로 전환됩니다.</li><li>최소 환전 금액은 <strong>1,000포인트</strong>입니다.</li><li>환전 완료 후, ​<strong>USDT가 연결된 지갑에 직접 전송</strong>​됩니다.</li></ul><h4 id="주간-리더보드는-어떻게-작동하나요" tabindex="-1">주간 리더보드는 어떻게 작동하나요? <a class="header-anchor" href="#주간-리더보드는-어떻게-작동하나요" aria-label="Permalink to &quot;주간 리더보드는 어떻게 작동하나요?&quot;">​</a></h4><ul><li>매주 DGrid는 ​<strong>300달러 상금 풀</strong>​을 할당합니다.</li><li>사용자는 해당 주에 ​<strong>획득한 포인트</strong>​를 기준으로 순위가 매겨집니다.</li><li>상금 풀은 ​<strong>비례적으로</strong>​ 분배됩니다: 주간 포인트가 많을수록 ​<strong>300달러</strong>​ 풀에서의 분배 비율이 더 커집니다.</li></ul><h4 id="제-참여가-dgrid-ai를-어떻게-개선하나요" tabindex="-1">제 참여가 DGrid AI를 어떻게 개선하나요? <a class="header-anchor" href="#제-참여가-dgrid-ai를-어떻게-개선하나요" aria-label="Permalink to &quot;제 참여가 DGrid AI를 어떻게 개선하나요?&quot;">​</a></h4><p>당신의 투표는:</p><ul><li>사용자가 선호하는 AI 응답이 무엇인지 DGrid에 알려줍니다</li><li>실제 사용 환경에서 가장 잘 수행하는 모델 식별에 도움을 줍니다</li><li>모델 선택, 파인튜닝 전략, 안전성 및 품질 개선에 정보를 제공하는 지속적인 피드백을 제공합니다</li></ul>',111)]))}const I=t(e,[["render",g]]);export{b as __pageData,I as default};
